15	class AssessmentController extends Controller
16	{
17	    public function __construct(private AssessmentService $service) {}
18	
19	    public function index()
20	    {
21	        $assessments = Assessment::with(['framework', 'creator'])
22	            ->latest()
23	            ->paginate(20);
24	
25	        return view('assessments.index', compact('assessments'));
