35	    public function store(Request $request)
36	    {
37	        $data = $request->validate([
38	            'name'        => 'required|string|max:255',
39	            'description' => 'nullable|string',
40	            'framework_id'=> 'required|exists:frameworks,id',
41	            'start_date'  => 'nullable|date',
42	            'end_date'    => 'nullable|date|after_or_equal:start_date',
43	            'assessor_ids'=> 'nullable|array',
44	            'assessor_ids.*' => 'exists:users,id',
45	        ]);
46	
47	        $assessment = Assessment::create([
48	            ...$data,
49	            'status'     => 'not_started',
50	            'created_by' => Auth::id(),
51	        ]);
52	
53	        if ($data['assessor_ids'] ?? null) {
54	            $assessment->assessors()->sync($data['assessor_ids']);
55	        }
56	
57	        $this->service->initializeFindings($assessment);
58	
59	        return redirect()->route('assessments.findings', $assessment)
60	            ->with('success', 'Assessment created. Start reviewing controls below.');
61	    }
62	
63	    public function show(Assessment $assessment)
64	    {
65	        $assessment->load(['framework', 'creator', 'assessors', 'findings.subcontrol.frameworkApp']);
66	        return view('assessments.show', compact('assessment'));
67	    }
