69	    public function edit(Assessment $assessment)
70	    {
71	        $frameworks = Framework::where('status', 'active')->get();
72	        $assessors  = User::where('is_active', true)->get();
73	        return view('assessments.edit', compact('assessment', 'frameworks', 'assessors'));
74	    }
