76	    public function update(Request $request, Assessment $assessment)
77	    {
78	        $data = $request->validate([
79	            'name'        => 'required|string|max:255',
80	            'description' => 'nullable|string',
81	            'status'      => 'required|in:not_started,in_progress,under_review,completed',
82	            'start_date'  => 'nullable|date',
83	            'end_date'    => 'nullable|date',
84	            'assessor_ids'=> 'nullable|array',
85	        ]);
86	
87	        $assessment->update($data);
88	        if (isset($data['assessor_ids'])) {
89	            $assessment->assessors()->sync($data['assessor_ids'] ?? []);
90	        }
91	
92	        return redirect()->route('assessments.show', $assessment)
93	            ->with('success', 'Assessment updated.');
94	    }
95	
96	    public function destroy(Assessment $assessment)
97	    {
98	        $assessment->delete();
99	        return redirect()->route('assessments.index')
100	            ->with('success', 'Assessment deleted.');
101	    }
102	
103	    public function findings(Assessment $assessment)
104	    {
105	        $assessment->load([
106	            'framework.apps.subcontrols.frameworkApp',
107	            'findings.subcontrol',
108	            'findings.documents',
109	        ]);
110	
111	        $findingsBySubcontrol = $assessment->findings->keyBy('subcontrol_id');
112	
113	        return view('assessments.findings', compact('assessment', 'findingsBySubcontrol'));
114	    }
115	
116	    public function updateFinding(Request $request, Assessment $assessment)
117	    {
118	        $data = $request->validate([
119	            'subcontrol_id'          => 'required|exists:subcontrols,id',
120	            'status'                 => 'nullable|in:met,partially_met,not_met,not_applicable',
121	            'implementation_details' => 'nullable|string',
122	            'notes'                  => 'nullable|string',
123	            'recommendations'        => 'nullable|string',
124	        ]);
125	
126	        $finding = $assessment->findings()->updateOrCreate(
127	            ['subcontrol_id' => $data['subcontrol_id']],
128	            [
129	                'status'                 => $data['status'] ?? null,
130	                'implementation_details' => $data['implementation_details'] ?? null,
131	                'notes'                  => $data['notes'] ?? null,
132	                'recommendations'        => $data['recommendations'] ?? null,
133	                'assessed_by'            => Auth::id(),
134	                'assessed_at'            => now(),
135	            ]
136	        );
137	
138	        $assessment->recalculateCompletion();
139	
140	        if ($request->wantsJson()) {
141	            return response()->json([
142	                'finding'    => $finding,
143	                'completion' => $assessment->fresh()->completion_percentage,
144	            ]);
145	        }
146	
147	        return back()->with('success', 'Finding updated.');
148	    }
149	
150	    public function generateAIRecommendations(Request $request, Assessment $assessment)
151	    {
152	        $request->validate(['subcontrol_id' => 'required|exists:subcontrols,id']);
153	
154	        $finding = $assessment->findings()->where('subcontrol_id', $request->subcontrol_id)->firstOrFail();
155	        $subcontrol = $finding->subcontrol;
156	
157	        try {
158	            $recommendation = $this->service->generateAIRecommendation($subcontrol, $finding->status);
159	
160	            $finding->update([
161	                'recommendations'            => $recommendation,
162	                'ai_generated_recommendations'=> true,
163	                'ai_generated_at'            => now(),
164	            ]);
165	
166	            return response()->json(['recommendation' => $recommendation, 'generated_at' => $finding->fresh()->ai_generated_at]);
167	        } catch (\Exception $e) {
168	            return response()->json(['error' => $e->getMessage()], 500);
169	        }
170	    }
171	
172	    public function exportXlsx(Assessment $assessment)
173	    {
174	        $assessment->load(['framework', 'findings.subcontrol.frameworkApp', 'findings.documents']);
175	        return $this->service->exportXlsx($assessment);
176	    }
177	
178	    public function generateSSP(Assessment $assessment)
179	    {
180	        $assessment->load(['framework', 'findings.subcontrol', 'creator', 'assessors']);
181	        return $this->service->generateSSP($assessment);
182	    }
183	
184	    public function clone(Assessment $assessment)
185	    {
186	        $clone = $assessment->replicate(['completion_percentage', 'status']);
187	        $clone->name   = $assessment->name . ' (Copy)';
188	        $clone->status = 'not_started';
189	        $clone->completion_percentage = 0;
190	        $clone->created_by = Auth::id();
191	        $clone->save();
192	
193	        $this->service->initializeFindings($clone);
194	
195	        return redirect()->route('assessments.findings', $clone)
196	            ->with('success', 'Assessment cloned.');
197	    }
198	}
