103	    public function downloadTemplate()
104	    {
105	        $headers = [
106	            'Framework List', 'App Name', 'App Description', 'Parent Subcontrol Name',
107	            'Subcontrol Name', 'Overview Text', 'Action Item Text', 'Related Documents',
108	            'Additional Guidance', 'App Icon', 'Level 1', 'Level 2', 'Level 3', 'Level 4', 'Level 5',
109	        ];
110	
111	        $filename = 'framework-import-template.csv';
112	        $callback = function () use ($headers) {
113	            $handle = fopen('php://output', 'w');
114	            fputcsv($handle, $headers);
115	            // Example row
116	            fputcsv($handle, [
117	                'CMMC', 'Access Control (AC.1.001)', 'Manage access to systems and data.',
118	                'Level 1', 'Limit access to authorized users (1.1)',
119	                'Overview of access control requirements.', 'Action items to implement.',
120	                'NIST SP 800-171 Section 3.1', 'Additional guidance here.',
121	                'access-control.png', 'Level 1', '', '', '', '',
122	            ]);
123	            fclose($handle);
124	        };
125	
126	        return response()->stream($callback, 200, [
127	            'Content-Type'        => 'text/csv',
128	            'Content-Disposition' => "attachment; filename=\"{$filename}\"",
129	        ]);
130	    }
131	
132	    public function clone(Framework $framework)
133	    {
134	        $clone = $framework->replicate();
135	        $clone->name   = $framework->name . ' (Copy)';
136	        $clone->status = 'draft';
137	        $clone->save();
138	
139	        foreach ($framework->apps as $app) {
140	            $newApp = $app->replicate();
141	            $newApp->framework_id = $clone->id;
142	            $newApp->save();
143	
144	            foreach ($app->parentSubcontrols as $parent) {
145	                $newParent = $parent->replicate();
146	                $newParent->framework_app_id = $newApp->id;
147	                $newParent->save();
148	
149	                foreach ($parent->subcontrols as $sub) {
150	                    $newSub = $sub->replicate();
151	                    $newSub->framework_app_id    = $newApp->id;
152	                    $newSub->parent_subcontrol_id = $newParent->id;
153	                    $newSub->save();
154	                }
155	            }
156	        }
157	
158	        return redirect()->route('frameworks.show', $clone)
159	            ->with('success', 'Framework cloned successfully.');
160	    }
161	}
