2	
3	namespace App\Services;
4	
5	use App\Models\Framework;
6	use App\Models\FrameworkApp;
7	use App\Models\ParentSubcontrol;
8	use App\Models\Subcontrol;
9	use Illuminate\Http\UploadedFile;
10	use League\Csv\Reader;
11	use PhpOffice\PhpSpreadsheet\IOFactory;
12	
13	class FrameworkImportService
14	{
15	    private Framework $framework;
16	    private array $appCache         = [];
17	    private array $parentSubCache   = [];
18	
19	    public function __construct(Framework $framework)
20	    {
21	        $this->framework = $framework;
22	    }
23	
24	    public function import(UploadedFile $file): int
25	    {
26	        $rows = $this->readFile($file);
27	        $count = 0;
28	
29	        foreach ($rows as $index => $row) {
30	            if ($index === 0) continue; // skip header
31	
32	            // Map by column position (0-based)
33	            $frameworkName    = trim($row[0] ?? '');
34	            $appName          = trim($row[1] ?? '');
35	            $appDescription   = trim($row[2] ?? '');
36	            $parentName       = trim($row[3] ?? '');
37	            $subcontrolName   = trim($row[4] ?? '');
38	            $overview         = trim($row[5] ?? '');
39	            $actionItems      = trim($row[6] ?? '');
40	            $relatedDocs      = trim($row[7] ?? '');
41	            $additionalGuide  = trim($row[8] ?? '');
42	            $icon             = trim($row[9] ?? '');
43	            $level1           = trim($row[10] ?? '');
44	            $level2           = trim($row[11] ?? '');
45	            $level3           = trim($row[12] ?? '');
46	            $level4           = trim($row[13] ?? '');
47	            $level5           = trim($row[14] ?? '');
48	
49	            if (empty($subcontrolName)) continue;
50	
51	            $app = $this->getOrCreateApp($appName, $appDescription, $icon);
52	
53	            $parent = null;
54	            if (!empty($parentName)) {
55	                $parent = $this->getOrCreateParent($app, $parentName);
56	            }
57	
58	            Subcontrol::create([
59	                'framework_app_id'    => $app->id,
60	                'parent_subcontrol_id'=> $parent?->id,
61	                'name'                => $subcontrolName,
62	                'overview'            => $overview ?: null,
63	                'action_items'        => $actionItems ?: null,
64	                'related_documents'   => $relatedDocs ?: null,
65	                'additional_guidance' => $additionalGuide ?: null,
66	                'level_1'             => $level1 ?: null,
67	                'level_2'             => $level2 ?: null,
68	                'level_3'             => $level3 ?: null,
69	                'level_4'             => $level4 ?: null,
70	                'level_5'             => $level5 ?: null,
71	                'sort_order'          => $count,
72	            ]);
73	
74	            $count++;
75	        }
76	
77	        return $count;
78	    }
79	
80	    private function readFile(UploadedFile $file): array
81	    {
82	        $extension = strtolower($file->getClientOriginalExtension());
83	
84	        if ($extension === 'csv') {
85	            $content = file_get_contents($file->getRealPath());
86	            // Detect delimiter
87	            $delimiter = substr_count($content, "\t") > substr_count($content, ",") ? "\t" : ",";
88	            $rows = [];
89	            foreach (explode("\n", $content) as $line) {
90	                if (trim($line) === '') continue;
91	                $rows[] = str_getcsv($line, $delimiter);
92	            }
93	            return $rows;
94	        }
95	
96	        // Excel
97	        $spreadsheet = IOFactory::load($file->getRealPath());
98	        $sheet = $spreadsheet->getActiveSheet();
99	        $rows = [];
100	        foreach ($sheet->getRowIterator() as $row) {
101	            $cells = [];
102	            foreach ($row->getCellIterator() as $cell) {
103	                $cells[] = $cell->getValue();
104	            }
105	            $rows[] = $cells;
106	        }
107	        return $rows;
108	    }
109	
110	    private function getOrCreateApp(string $name, string $description, string $icon): FrameworkApp
111	    {
112	        $key = strtolower($name);
113	        if (!isset($this->appCache[$key])) {
114	            $this->appCache[$key] = FrameworkApp::firstOrCreate(
115	                ['framework_id' => $this->framework->id, 'name' => $name],
116	                ['description' => $description ?: null, 'icon' => $icon ?: null, 'sort_order' => count($this->appCache)]
117	            );
118	        }
119	        return $this->appCache[$key];
120	    }
121	
122	    private function getOrCreateParent(FrameworkApp $app, string $name): ParentSubcontrol
123	    {
124	        $key = $app->id . ':' . strtolower($name);
125	        if (!isset($this->parentSubCache[$key])) {
126	            $this->parentSubCache[$key] = ParentSubcontrol::firstOrCreate(
127	                ['framework_app_id' => $app->id, 'name' => $name],
128	                ['sort_order' => count($this->parentSubCache)]
129	            );
130	        }
131	        return $this->parentSubCache[$key];
132	    }
133	}
